import{_ as a,o as i,c,ae as t}from"./chunks/framework.RRduUuAx.js";const p=JSON.parse('{"title":"Pipeline Governance and Artifact Policy","description":"","frontmatter":{},"headers":[],"relativePath":"governance/PIPELINE_GOVERNANCE_AND_ARTIFACT_POLICY.md","filePath":"governance/PIPELINE_GOVERNANCE_AND_ARTIFACT_POLICY.md"}'),l={name:"governance/PIPELINE_GOVERNANCE_AND_ARTIFACT_POLICY.md"};function o(r,e,n,d,s,h){return i(),c("div",null,[...e[0]||(e[0]=[t('<h1 id="pipeline-governance-and-artifact-policy" tabindex="-1">Pipeline Governance and Artifact Policy <a class="header-anchor" href="#pipeline-governance-and-artifact-policy" aria-label="Permalink to &quot;Pipeline Governance and Artifact Policy&quot;">​</a></h1><h2 id="policy-goals" tabindex="-1">Policy Goals <a class="header-anchor" href="#policy-goals" aria-label="Permalink to &quot;Policy Goals&quot;">​</a></h2><ol><li>Every pipeline run should leave auditable machine-readable artifacts.</li><li>Artifact paths should support both immutable history and easy latest lookup.</li><li>Mutating pricing workflows must remain explicit and reviewable.</li></ol><h2 id="required-artifacts" tabindex="-1">Required Artifacts <a class="header-anchor" href="#required-artifacts" aria-label="Permalink to &quot;Required Artifacts&quot;">​</a></h2><ol><li>Ingest summary:</li></ol><ul><li><code>--summary-json-path</code></li></ul><ol start="2"><li>Reconcile artifacts:</li></ol><ul><li>per-run directory <code>reconcile-YYYYMMDD-HHMMSS/</code></li><li><code>pricing-patch.reconcile.json</code></li><li><code>unpriced-events.reconcile.jsonl</code></li><li><code>reconcile-summary.json</code></li><li>rolling pointer: <code>reconcile-latest-summary.json</code></li></ul><ol start="3"><li>Bench artifacts:</li></ol><ul><li>timestamped <code>bench-*.json</code></li><li>rolling <code>latest-summary.json</code></li></ul><ol start="4"><li>UI artifact (optional):</li></ol><ul><li><code>ui-snapshot.json</code></li></ul><ol start="5"><li>Cache artifacts (optional but recommended for operator runs):</li></ol><ul><li>ingest cache metadata: <code>--ingest-cache-path</code></li><li>aggregate cache entries: <code>--aggregate-cache-path</code></li></ul><h2 id="safety-defaults" tabindex="-1">Safety Defaults <a class="header-anchor" href="#safety-defaults" aria-label="Permalink to &quot;Safety Defaults&quot;">​</a></h2><ol><li><code>task do:all:next</code> and <code>task orchestrate</code> run pricing reconcile in dry-run mode.</li><li>Static artifact mode must be explicit (<code>--pricing-reconcile-static-artifacts</code>).</li><li>Mutating pricing writes require explicit flags.</li></ol><h2 id="retention-guidance" tabindex="-1">Retention Guidance <a class="header-anchor" href="#retention-guidance" aria-label="Permalink to &quot;Retention Guidance&quot;">​</a></h2><ol><li>Keep rolling pointers for integrations.</li><li>Keep timestamped directories for audit and diffing.</li><li>Periodically archive old run artifacts when volume grows.</li></ol><h2 id="compliance-checks" tabindex="-1">Compliance Checks <a class="header-anchor" href="#compliance-checks" aria-label="Permalink to &quot;Compliance Checks&quot;">​</a></h2><ol><li>Artifact presence check after pipeline run.</li><li>Schema check for summary JSON payloads.</li><li>Pricing audit freshness and source provenance checks.</li><li>Perf and correctness gate checks.</li></ol><h2 id="cache-key-and-metrics-semantics" tabindex="-1">Cache Key and Metrics Semantics <a class="header-anchor" href="#cache-key-and-metrics-semantics" aria-label="Permalink to &quot;Cache Key and Metrics Semantics&quot;">​</a></h2><h3 id="ingest-cache-key-ingest-cache-path" tabindex="-1">Ingest cache key (<code>--ingest-cache-path</code>) <a class="header-anchor" href="#ingest-cache-key-ingest-cache-path" aria-label="Permalink to &quot;Ingest cache key (`--ingest-cache-path`)&quot;">​</a></h3><p>The ingest cache entry is reusable only when all fields match:</p><ol><li>provider set</li><li><code>since</code> value</li><li><code>limit</code> value</li><li>output path (<code>--events-out</code>)</li><li>source file <code>mtime</code> map collected from provider adapters</li></ol><p>Operational behavior:</p><ol><li><code>hit</code>: ingest is skipped and existing <code>--events-out</code> file is reused.</li><li><code>miss</code>: ingest runs and cache metadata is overwritten with the new key.</li><li><code>invalidate</code>: represented as a miss caused by any key mismatch or missing output file.</li></ol><h3 id="aggregate-cache-key-aggregate-cache-path" tabindex="-1">Aggregate cache key (<code>--aggregate-cache-path</code>) <a class="header-anchor" href="#aggregate-cache-key-aggregate-cache-path" aria-label="Permalink to &quot;Aggregate cache key (`--aggregate-cache-path`)&quot;">​</a></h3><p>Each aggregate cache entry is keyed by:</p><ol><li>selector:</li></ol><ul><li><code>month</code></li><li>provider/model filters</li><li><code>on_unpriced</code> mode</li></ul><ol start="2"><li>pricing hash (from <code>--pricing</code> content)</li><li>events fingerprint (from <code>--events-out</code> content/metadata)</li></ol><p>Operational behavior:</p><ol><li><code>hit</code>: monthly and daily reports are reused from cache with no recompute.</li><li><code>miss</code>: no selector entry exists; monthly/daily recompute and cache write occur.</li><li><code>invalidate</code>: selector entry exists but pricing hash or events fingerprint changed; stale entry is replaced after recompute.</li></ol><h3 id="pipeline-summary-metrics-aggregate-cache" tabindex="-1">Pipeline summary metrics (<code>aggregate_cache</code>) <a class="header-anchor" href="#pipeline-summary-metrics-aggregate-cache" aria-label="Permalink to &quot;Pipeline summary metrics (`aggregate_cache`)&quot;">​</a></h3><p><code>orchestrate --pipeline-summary-path</code> records aggregate cache metrics:</p><ol><li><code>hit_count</code></li><li><code>miss_count</code></li><li><code>invalidate_count</code></li><li><code>enabled</code></li><li><code>cache_path</code></li></ol><h2 id="phenotype-governance-overlay-v1" tabindex="-1">Phenotype Governance Overlay v1 <a class="header-anchor" href="#phenotype-governance-overlay-v1" aria-label="Permalink to &quot;Phenotype Governance Overlay v1&quot;">​</a></h2><ul><li>Enforce <code>TDD + BDD + SDD</code> for all feature and workflow changes.</li><li>Enforce <code>Hexagonal + Clean + SOLID</code> boundaries by default.</li><li>Favor explicit failures over silent degradation; required dependencies must fail clearly when unavailable.</li><li>Keep local hot paths deterministic and low-latency; place distributed workflow logic behind durable orchestration boundaries.</li><li>Require policy gating, auditability, and traceable correlation IDs for agent and workflow actions.</li><li>Document architectural and protocol decisions before broad rollout changes.</li></ul>',38)])])}const g=a(l,[["render",o]]);export{p as __pageData,g as default};
